insert into public.knowledge_points (id,name,summary,core_fact,category,common_mistake,memory_tip,published,version) values
  ('history-party-new-democracy','新民主主义革命时期','从中国共产党成立到中华人民共和国成立的历史阶段。','1921—1949 年是新民主主义革命时期。','党史时间线','把中共七大年份误记为 1927 年。','先记四段：1921—1949、1949—1978、1978—2012、2012 至今。',true,1),
  ('history-party-construction','社会主义革命和建设时期','中华人民共和国成立后至改革开放前的重要历史阶段。','1949—1978 年是社会主义革命和建设时期。','党史时间线','把 1949 年建国与 1978 年改革开放混为同一节点。','四九建国，七八转折。',true,1),
  ('history-party-reform','改革开放和社会主义现代化建设新时期','以十一届三中全会为重要起点的历史阶段。','1978—2012 年为改革开放和社会主义现代化建设新时期。','党史时间线','把社会主义市场经济体制目标对应错到十五大。','十四大确立社会主义市场经济体制改革目标。',true,1),
  ('history-party-new-era','中国特色社会主义新时代','新时代由中共十八大开启，并在后续大会持续推进。','2012 年中共十八大标志中国特色社会主义进入新时代。','党史时间线','把十九大召开年份误记为 2019 年。','十八开新程，十九矛盾换新容，二十大复兴定宏图。',true,1),
  ('history-cpc-first','中共一大','中国共产党成立的重要节点。','1921 年中共一大召开，中国共产党成立。','党史事件','将建党年份与新中国成立年份混淆。','一大建党，年份 1921。',true,1),
  ('history-republic-founded','中华人民共和国成立','新民主主义革命取得伟大胜利的重要标志。','1949 年中华人民共和国成立。','党史事件','把建国时间与改革开放起点混淆。','四九建国。',true,1),
  ('history-third-plenum','十一届三中全会','开启改革开放，重新确立实事求是思想路线，工作重心转向经济建设。','1978 年十一届三中全会是改革开放的重要起点。','党史事件','把工作重心转移误写为其他会议。','十一届三中全会：改革开放、经济建设。',true,1),
  ('history-market-economy','社会主义市场经济体制','中共十四大提出建立社会主义市场经济体制的改革目标。','1992 年中共十四大确立社会主义市场经济体制改革目标。','党史事件','把十四大、十五大、十六大的理论成果相互错位。','市场经济看十四大。',true,1),
  ('history-new-era-start','新时代起点','中国特色社会主义进入新时代的时间坐标。','2012 年中共十八大标志进入新时代。','党史事件','以为新时代从十九大才开始。','新时代起点看十八大。',true,1),
  ('history-main-contradiction','社会主要矛盾转化','新时代社会主要矛盾的表述在中共十九大明确。','人民日益增长的美好生活需要和不平衡不充分的发展之间的矛盾。','党史事件','只记住美好生活需要，漏掉不平衡不充分的发展。','主要矛盾看十九大，完整两端都要记。',true,1),
  ('history-chinese-modernization','中国式现代化','二十大提出以中国式现代化全面推进中华民族伟大复兴。','中共二十大擘画全面建设社会主义现代化国家的宏伟蓝图。','党史事件','把中国式现代化相关表述错放到十八大或十九大。','中国式现代化、民族复兴看二十大。',true,1),
  ('history-zhou-system','西周分封与宗法','分封制与宗法制结合，礼乐制度规范等级秩序。','西周以血缘关系维系政治关系，实行分封制和宗法制。','古代政治制度','把宗法制理解成按地域行政划分。','周：分封建国，宗法维系，礼乐辨序。',true,1),
  ('history-qin-system','秦朝三公九卿与郡县','皇帝总揽大权，中央设三公九卿，地方实行郡县制。','丞相辅政、太尉掌军、御史大夫监察；郡县官由中央任免。','古代政治制度','把三公职能或郡县制的中央任免特点记反。','丞相管行政，太尉管军事，御史大夫管监察。',true,1),
  ('history-han-system','汉朝郡国并行','汉初郡国并行，后以推恩令、刺史等措施加强中央集权。','推恩令削弱诸侯势力，刺史负责监察。','古代政治制度','把推恩令误认为建立行省制的措施。','汉：郡国并行，推恩削藩，刺史监察。',true,1),
  ('history-sui-tang-system','隋唐三省六部','三省分工协作，六部在尚书省下分掌具体政务。','中书省决策起草，门下省审议封驳，尚书省负责执行。','古代政治制度','把三省职能顺序倒置。','中书决策，门下审议，尚书执行。',true,1),
  ('history-song-system','宋朝二府三司','分割相权，分别管理行政、军事、财政。','中书门下掌行政，枢密院掌军事，三司掌财政。','古代政治制度','把三司误记成军事机构。','宋：中书管政，枢密管军，三司管钱。',true,1),
  ('history-yuan-system','元朝行省','中央设中书省，地方设行中书省，行省制影响后世地方行政区划。','行省制便利管理辽阔疆域并加强中央对地方控制。','古代政治制度','把行省制起源错放到明清。','元：中书总百司，地方设行省。',true,1),
  ('history-ming-system','明朝废丞相与内阁','废除丞相，六部直属皇帝，内阁作为辅政机构。','内阁票拟，皇帝批红；内阁不具法定宰相权。','古代政治制度','把内阁当作拥有独立决策权的宰相机构。','明：废相分六部，内阁帮票拟，皇权更集中。',true,1),
  ('history-qing-system','清朝军机处','军机大臣承旨办事，跪受笔录、上传下达，办事简速密。','军机处使君主专制发展到顶峰。','古代政治制度','把军机处当成能独立决定政务的机构。','清军机：简、速、密，承旨办事。',true,1)
