insert into public.questions (id,knowledge_id,level_id,question_type,stem,options,correct_answer,explanation,difficulty,published,version) values
  ('history-party-01','history-cpc-first','history-party-1','single_choice','中国共产党成立于哪一年？','{"questionId":"history-party-01","knowledgeId":"history-cpc-first","type":"single_choice","stem":"中国共产党成立于哪一年？","options":[{"id":"A","text":"1919 年"},{"id":"B","text":"1949 年"},{"id":"C","text":"1921 年"},{"id":"D","text":"1927 年"}]}'::jsonb,'"C"'::jsonb,'{"summary":"正确答案：1921 年","whyCorrect":"1921 年中共一大召开，中国共产党成立。","whyUserAnswerWrong":"请把建党、建国和重要革命会议的时间分开记忆。","commonMistake":"将 1921 年建党与 1949 年建国混淆。","memoryTip":"一大建党，年份 1921。"}'::jsonb,1,true,1),
  ('history-party-02','history-party-construction','history-party-1','single_choice','1949—1978 年对应党史四个时期中的哪一阶段？','{"questionId":"history-party-02","knowledgeId":"history-party-construction","type":"single_choice","stem":"1949—1978 年对应党史四个时期中的哪一阶段？","options":[{"id":"A","text":"社会主义革命和建设时期"},{"id":"B","text":"中国特色社会主义新时代"},{"id":"C","text":"新民主主义革命时期"},{"id":"D","text":"改革开放和社会主义现代化建设新时期"}]}'::jsonb,'"A"'::jsonb,'{"summary":"正确答案：社会主义革命和建设时期","whyCorrect":"1949—1978 年是社会主义革命和建设时期。","whyUserAnswerWrong":"请按四个时期的起止年份定位。","commonMistake":"把建国后时期与改革开放时期混淆。","memoryTip":"四九建国，七八转折。"}'::jsonb,2,true,1),
  ('history-party-03','history-third-plenum','history-party-1','single_choice','下列关于十一届三中全会的表述，正确的是？','{"questionId":"history-party-03","knowledgeId":"history-third-plenum","type":"single_choice","stem":"下列关于十一届三中全会的表述，正确的是？","options":[{"id":"A","text":"提出建立社会主义市场经济体制"},{"id":"B","text":"标志中国特色社会主义进入新时代"},{"id":"C","text":"把邓小平理论写入党章"},{"id":"D","text":"开启改革开放，工作重心转向经济建设"}]}'::jsonb,'"D"'::jsonb,'{"summary":"正确答案：开启改革开放，工作重心转向经济建设","whyCorrect":"1978 年十一届三中全会开启改革开放，重新确立实事求是思想路线，工作重心转向经济建设。","whyUserAnswerWrong":"选项分别对应不同时期的重要会议。","commonMistake":"将市场经济体制目标与十一届三中全会混淆。","memoryTip":"十一届三中全会：改革开放、经济建设。"}'::jsonb,3,true,1),
  ('history-party-04','history-market-economy','history-party-1','single_choice','确立建立社会主义市场经济体制改革目标的是哪次会议？','{"questionId":"history-party-04","knowledgeId":"history-market-economy","type":"single_choice","stem":"确立建立社会主义市场经济体制改革目标的是哪次会议？","options":[{"id":"A","text":"中共十二大"},{"id":"B","text":"中共十四大"},{"id":"C","text":"中共十五大"},{"id":"D","text":"中共十六大"}]}'::jsonb,'"B"'::jsonb,'{"summary":"正确答案：中共十四大","whyCorrect":"1992 年中共十四大确立社会主义市场经济体制改革目标。","whyUserAnswerWrong":"注意区分各次大会的理论与制度成果。","commonMistake":"将十四大与十五大、十六大错位。","memoryTip":"市场经济看十四大。"}'::jsonb,2,true,1),
  ('history-party-05','history-new-era-start','history-party-1','single_choice','中国特色社会主义进入新时代的起点是？','{"questionId":"history-party-05","knowledgeId":"history-new-era-start","type":"single_choice","stem":"中国特色社会主义进入新时代的起点是？","options":[{"id":"A","text":"中共十七大"},{"id":"B","text":"中共十九大"},{"id":"C","text":"中共二十大"},{"id":"D","text":"中共十八大"}]}'::jsonb,'"D"'::jsonb,'{"summary":"正确答案：中共十八大","whyCorrect":"2012 年中共十八大标志中国特色社会主义进入新时代。","whyUserAnswerWrong":"十九大明确社会主要矛盾转化，但新时代起点看十八大。","commonMistake":"把新时代起点误认为十九大。","memoryTip":"新时代起点看十八大。"}'::jsonb,2,true,1),
  ('history-party-06','history-main-contradiction','history-party-1','single_choice','新时代我国社会主要矛盾的正确表述是？','{"questionId":"history-party-06","knowledgeId":"history-main-contradiction","type":"single_choice","stem":"新时代我国社会主要矛盾的正确表述是？","options":[{"id":"A","text":"人民日益增长的物质文化需要同落后的社会生产之间的矛盾"},{"id":"B","text":"人民日益增长的美好生活需要和不平衡不充分的发展之间的矛盾"},{"id":"C","text":"生产力与生产关系之间的矛盾"},{"id":"D","text":"经济建设与环境保护之间的矛盾"}]}'::jsonb,'"B"'::jsonb,'{"summary":"正确答案：人民日益增长的美好生活需要和不平衡不充分的发展之间的矛盾","whyCorrect":"这一表述在中共十九大明确。","whyUserAnswerWrong":"旧表述与新时代表述的关键词不同。","commonMistake":"漏掉不平衡不充分的发展这一端。","memoryTip":"主要矛盾看十九大，完整两端都要记。"}'::jsonb,3,true,1),
  ('history-party-07','history-chinese-modernization','history-party-1','single_choice','下列与中共二十大密切相关的是？','{"questionId":"history-party-07","knowledgeId":"history-chinese-modernization","type":"single_choice","stem":"下列与中共二十大密切相关的是？","options":[{"id":"A","text":"以中国式现代化全面推进中华民族伟大复兴"},{"id":"B","text":"首次提出建设有中国特色社会主义"},{"id":"C","text":"确立社会主义市场经济体制改革目标"},{"id":"D","text":"把科学发展观写入党章"}]}'::jsonb,'"A"'::jsonb,'{"summary":"正确答案：以中国式现代化全面推进中华民族伟大复兴","whyCorrect":"中共二十大擘画全面建设社会主义现代化国家的宏伟蓝图。","whyUserAnswerWrong":"其他选项分别对应其他历史节点。","commonMistake":"将中国式现代化的重点表述错放到较早大会。","memoryTip":"中国式现代化、民族复兴看二十大。"}'::jsonb,3,true,1),
  ('history-party-08','history-party-reform','history-party-1','single_choice','1978—2012 年对应党史四个时期中的哪一阶段？','{"questionId":"history-party-08","knowledgeId":"history-party-reform","type":"single_choice","stem":"1978—2012 年对应党史四个时期中的哪一阶段？","options":[{"id":"A","text":"新民主主义革命时期"},{"id":"B","text":"社会主义革命和建设时期"},{"id":"C","text":"改革开放和社会主义现代化建设新时期"},{"id":"D","text":"中国特色社会主义新时代"}]}'::jsonb,'"C"'::jsonb,'{"summary":"正确答案：改革开放和社会主义现代化建设新时期","whyCorrect":"1978—2012 年是改革开放和社会主义现代化建设新时期。","whyUserAnswerWrong":"请按四个时期的起止年份定位。","commonMistake":"把 1978 年后的时期误判为新时代。","memoryTip":"七八改革，至 2012 年进入新时代。"}'::jsonb,2,true,1),
  ('history-system-01','history-zhou-system','history-system-1','single_choice','西周以血缘关系维系政治关系的制度是？','{"questionId":"history-system-01","knowledgeId":"history-zhou-system","type":"single_choice","stem":"西周以血缘关系维系政治关系的制度是？","options":[{"id":"A","text":"郡县制"},{"id":"B","text":"行省制"},{"id":"C","text":"宗法制"},{"id":"D","text":"军机处"}]}'::jsonb,'"C"'::jsonb,'{"summary":"正确答案：宗法制","whyCorrect":"西周宗法制以血缘亲疏维系政治关系，形成大宗、小宗体系。","whyUserAnswerWrong":"郡县、行省和军机处属于后世制度。","commonMistake":"将宗法制误作地方行政制度。","memoryTip":"周：分封建国，宗法维系。"}'::jsonb,2,true,1),
  ('history-system-02','history-qin-system','history-system-1','single_choice','秦朝中央三公中，负责监察百官的是？','{"questionId":"history-system-02","knowledgeId":"history-qin-system","type":"single_choice","stem":"秦朝中央三公中，负责监察百官的是？","options":[{"id":"A","text":"丞相"},{"id":"B","text":"御史大夫"},{"id":"C","text":"太尉"},{"id":"D","text":"太傅"}]}'::jsonb,'"B"'::jsonb,'{"summary":"正确答案：御史大夫","whyCorrect":"秦朝三公中，丞相辅政、太尉掌军、御史大夫监察百官。","whyUserAnswerWrong":"请按行政、军事、监察三项职能区分。","commonMistake":"把御史大夫与太尉的职能记反。","memoryTip":"丞相政、太尉军、御史察。"}'::jsonb,2,true,1),
  ('history-system-03','history-qin-system','history-system-1','single_choice','下列最能体现秦朝中央集权制度在地方层面特点的是？','{"questionId":"history-system-03","knowledgeId":"history-qin-system","type":"single_choice","stem":"下列最能体现秦朝中央集权制度在地方层面特点的是？","options":[{"id":"A","text":"诸侯在封国世袭统治"},{"id":"B","text":"地方行政由宗法关系决定"},{"id":"C","text":"郡县长官由中央任免"},{"id":"D","text":"地方行省拥有独立军政财权"}]}'::jsonb,'"C"'::jsonb,'{"summary":"正确答案：郡县长官由中央任免","whyCorrect":"郡县制下地方官由中央任免，体现中央对地方的直接控制。","whyUserAnswerWrong":"世袭封国是分封制特点，行省制出现更晚。","commonMistake":"把分封制的世袭特点套到郡县制。","memoryTip":"秦：三公九卿，地方郡县，官由中央任。"}'::jsonb,3,true,1),
  ('history-system-04','history-sui-tang-system','history-system-1','single_choice','隋唐三省中，负责审议封驳的是？','{"questionId":"history-system-04","knowledgeId":"history-sui-tang-system","type":"single_choice","stem":"隋唐三省中，负责审议封驳的是？","options":[{"id":"A","text":"中书省"},{"id":"B","text":"门下省"},{"id":"C","text":"尚书省"},{"id":"D","text":"枢密院"}]}'::jsonb,'"B"'::jsonb,'{"summary":"正确答案：门下省","whyCorrect":"中书省决策起草，门下省审议封驳，尚书省负责执行。","whyUserAnswerWrong":"三省按起草、审议、执行分工。","commonMistake":"把门下省与尚书省职能颠倒。","memoryTip":"中书决策，门下审议，尚书执行。"}'::jsonb,2,true,1),
  ('history-system-05','history-song-system','history-system-1','single_choice','宋朝二府三司制中，掌管财政的是？','{"questionId":"history-system-05","knowledgeId":"history-song-system","type":"single_choice","stem":"宋朝二府三司制中，掌管财政的是？","options":[{"id":"A","text":"中书门下"},{"id":"B","text":"枢密院"},{"id":"C","text":"御史台"},{"id":"D","text":"三司"}]}'::jsonb,'"D"'::jsonb,'{"summary":"正确答案：三司","whyCorrect":"宋朝中书门下掌行政、枢密院掌军事、三司掌财政。","whyUserAnswerWrong":"题干考查二府三司的分权安排。","commonMistake":"把三司误认为军事机构。","memoryTip":"宋：中书管政，枢密管军，三司管钱。"}'::jsonb,2,true,1),
  ('history-system-06','history-yuan-system','history-system-1','single_choice','下列关于元朝行省制的说法，正确的是？','{"questionId":"history-system-06","knowledgeId":"history-yuan-system","type":"single_choice","stem":"下列关于元朝行省制的说法，正确的是？","options":[{"id":"A","text":"地方行省由中央中书省统辖"},{"id":"B","text":"以宗法血缘作为地方治理基础"},{"id":"C","text":"六部直接统辖各地行省"},{"id":"D","text":"军机大臣管理地方行政"}]}'::jsonb,'"A"'::jsonb,'{"summary":"正确答案：地方行省由中央中书省统辖","whyCorrect":"元朝中央设中书省，地方设行中书省，行省制便利管理辽阔疆域。","whyUserAnswerWrong":"宗法、六部直辖和军机处都不符合元朝行省制。","commonMistake":"把行省制的中央统辖关系忽略。","memoryTip":"元：中书总百司，地方设行省。"}'::jsonb,3,true,1),
  ('history-system-07','history-ming-system','history-system-1','single_choice','关于明朝内阁的表述，正确的是？','{"questionId":"history-system-07","knowledgeId":"history-ming-system","type":"single_choice","stem":"关于明朝内阁的表述，正确的是？","options":[{"id":"A","text":"内阁取代皇帝总揽全国政务"},{"id":"B","text":"内阁拥有法定宰相权"},{"id":"C","text":"内阁统领六部并可独立决策"},{"id":"D","text":"内阁是辅政机构，票拟后由皇帝批红"}]}'::jsonb,'"D"'::jsonb,'{"summary":"正确答案：内阁是辅政机构，票拟后由皇帝批红","whyCorrect":"明朝废丞相后，内阁协助皇帝处理政务，但不具法定宰相权。","whyUserAnswerWrong":"内阁的权力来自皇帝信任，不能独立决策。","commonMistake":"把内阁当作拥有独立相权的机构。","memoryTip":"明：内阁帮票拟，皇帝来批红。"}'::jsonb,3,true,1),
  ('history-system-08','history-qing-system','history-system-1','single_choice','清朝军机处的主要特点是？','{"questionId":"history-system-08","knowledgeId":"history-qing-system","type":"single_choice","stem":"清朝军机处的主要特点是？","options":[{"id":"A","text":"军机大臣承旨办事，办事简速机密"},{"id":"B","text":"地方长官世袭统治"},{"id":"C","text":"中书省起草诏令"},{"id":"D","text":"分割相权以制约皇权"}]}'::jsonb,'"A"'::jsonb,'{"summary":"正确答案：军机大臣承旨办事，办事简速机密","whyCorrect":"军机处由军机大臣承旨办事，具有简、速、密的特点。","whyUserAnswerWrong":"军机处不是独立决策机构，其运作体现皇权高度集中。","commonMistake":"误以为军机大臣可以自行决定政务。","memoryTip":"清军机：简、速、密，承旨办事。"}'::jsonb,2,true,1),
  ('history-boss-01','history-party-new-democracy','history-boss','single_choice','下列时间顺序正确的是？','{"questionId":"history-boss-01","knowledgeId":"history-party-new-democracy","type":"single_choice","stem":"下列时间顺序正确的是？","options":[{"id":"A","text":"中共一大—十一届三中全会—中华人民共和国成立"},{"id":"B","text":"中华人民共和国成立—中共一大—中共十四大"},{"id":"C","text":"中共一大—中华人民共和国成立—十一届三中全会"},{"id":"D","text":"十一届三中全会—中共一大—中华人民共和国成立"}]}'::jsonb,'"C"'::jsonb,'{"summary":"正确答案：中共一大—中华人民共和国成立—十一届三中全会","whyCorrect":"三者依次为 1921 年、1949 年、1978 年。","whyUserAnswerWrong":"先写出三个年份，再比较先后即可。","commonMistake":"把建国与改革开放的先后顺序颠倒。","memoryTip":"一九二一建党，四九建国，七八改革。"}'::jsonb,3,true,1),
  ('history-boss-02','history-sui-tang-system','history-boss','single_choice','将中书省、门下省、尚书省的职能依次排列，正确的是？','{"questionId":"history-boss-02","knowledgeId":"history-sui-tang-system","type":"single_choice","stem":"将中书省、门下省、尚书省的职能依次排列，正确的是？","options":[{"id":"A","text":"执行—决策起草—审议封驳"},{"id":"B","text":"决策起草—审议封驳—执行"},{"id":"C","text":"审议封驳—执行—决策起草"},{"id":"D","text":"监察—军事—财政"}]}'::jsonb,'"B"'::jsonb,'{"summary":"正确答案：决策起草—审议封驳—执行","whyCorrect":"三省分工明确：中书决策起草、门下审议封驳、尚书执行。","whyUserAnswerWrong":"不要把三省制度与秦朝三公或宋朝二府三司混淆。","commonMistake":"将门下省和尚书省的职能倒置。","memoryTip":"中书决策，门下审议，尚书执行。"}'::jsonb,3,true,1),
  ('history-boss-03','history-ming-system','history-boss','single_choice','从秦朝郡县制到明清制度演变，最能体现的总体趋势是？','{"questionId":"history-boss-03","knowledgeId":"history-ming-system","type":"single_choice","stem":"从秦朝郡县制到明清制度演变，最能体现的总体趋势是？","options":[{"id":"A","text":"地方世袭权力不断扩大"},{"id":"B","text":"相权不断强化并超过皇权"},{"id":"C","text":"地方独立性不断增强"},{"id":"D","text":"君主专制和中央集权不断加强"}]}'::jsonb,'"D"'::jsonb,'{"summary":"正确答案：君主专制和中央集权不断加强","whyCorrect":"从郡县制、三省分工、分割相权到废丞相和军机处，皇权与中央对地方的控制总体加强。","whyUserAnswerWrong":"制度名称不同，但要抓住权力运行的长期趋势。","commonMistake":"只背制度名称，忽略中央集权强化这一主线。","memoryTip":"制度演变看两条线：皇权更集中，中央对地方更强。"}'::jsonb,4,true,1),
  ('history-boss-04','history-qing-system','history-boss','single_choice','下列制度与朝代对应正确的是？','{"questionId":"history-boss-04","knowledgeId":"history-qing-system","type":"single_choice","stem":"下列制度与朝代对应正确的是？","options":[{"id":"A","text":"军机处—清朝"},{"id":"B","text":"行省制—西周"},{"id":"C","text":"内阁制—秦朝"},{"id":"D","text":"三省六部制—宋朝创设"}]}'::jsonb,'"A"'::jsonb,'{"summary":"正确答案：军机处—清朝","whyCorrect":"军机处是清朝强化君主专制的重要机构。","whyUserAnswerWrong":"行省制在元朝，内阁在明朝，三省六部在隋唐成熟。","commonMistake":"将不同朝代的中枢制度横向混淆。","memoryTip":"周分封，秦郡县，唐三省，宋二府，元行省，明内阁，清军机。"}'::jsonb,3,true,1)
